// wrangler.jsonc -> { "d1_databases": [{ "binding": "DB", "database_name": "app" }] }
const { results } = await env.DB
  .prepare("SELECT * FROM orders WHERE city = ?")
  .bind("Taipei")
  .all();

// wrangler.jsonc -> { "r2_buckets": [{ "binding": "BUCKET", "bucket_name": "files" }] }
await env.BUCKET.put("invoice.pdf", request.body);
const object = await env.BUCKET.get("invoice.pdf");
return new Response(object.body);

// wrangler.jsonc -> durable_objects: { "name": "ROOM", "class_name": "Room" }
const stub = env.ROOM.getByName("room-42");
const count = await stub.increment(); // strongly consistent

